 13→func setupTestDB(t *testing.T) *Service {
 14→	t.Helper()
 15→	if testing.Short() {
 16→		t.Skip("skipping integration test")
 17→	}
 18→	dbURL := os.Getenv("DATABASE_URL")
 19→	if dbURL == "" {
 20→		t.Skip("DATABASE_URL not set")
 21→	}
 22→	ctx := context.Background()
 23→	pool, err := db.Connect(ctx, dbURL)
 24→	if err != nil {
 25→		t.Fatalf("db.Connect() error = %v", err)
 26→	}
 27→	t.Cleanup(func() { pool.Close() })
 28→	return New(pool)
